/* ==== */
/* File Uploader Components Setter */
FileUploader.Components.Setter = function (Params) {

    /* Declearation */
    var t_ElementName = "";

    /* Set the File Chunk Information */
    /* ==== Mandatory Params ==== */
    if (typeof Params.ElementName !== "undefined") t_ElementName = Params.ElementName;


    if (typeof Params.FileSize !== "undefined") FileUploader.Components[t_ElementName + "_FileSize"] = Params.FileSize;
    if (typeof Params.TotalChunks !== "undefined") FileUploader.Components[t_ElementName + "_TotalChunks"] = Params.TotalChunks;
    if (typeof Params.ActiveChunks !== "undefined") FileUploader.Components[t_ElementName + "_ActiveChunks"] = Params.ActiveChunks;

    /* Set the Progress Bar Status Information */
    if (typeof Params.ProgresssRate !== "undefined") FileUploader.Components[t_ElementName + "_ProgresssRate"] = Params.ProgresssRate;
    if (typeof Params.TrasferCompletedRate !== "undefined") FileUploader.Components[t_ElementName + "_TrasferCompletedRate"] = Params.TrasferCompletedRate;

}
/* ==== */

/* ==== */
/* File Uploader Progress Bar Components Setter */
FileUploader.Components.ProgressSetter = function (Params) {

    /* Declearation */
    var t_ElementName = "";
    var t_ProgressRate = 0;

    /* Uploader Element Name */
    if (typeof Params.ElementName !== "undefined") t_ElementName = Params.ElementName;
    if (typeof Params.ProgressRate !== "undefined") t_ProgressRate = (Params.ProgressRate * 1);

    if (t_ProgressRate > 0) {

        /* Add the Progress Completed Rate */
        FileUploader.Components[t_ElementName + "_TrasferCompletedRate"] += t_ProgressRate;

        /* ==== */
        /* Show the Progress Bar */
        $("#" + t_ElementName + "_DivProgress").show();
        $("#" + t_ElementName + "_DivProgressBar").show();
        $("#" + t_ElementName + "_DivProgressCancel").show();
        $("#" + t_ElementName + "_DivProgressBar").css("width", FileUploader.Components[t_ElementName + "_TrasferCompletedRate"] + "%");
        $("#" + t_ElementName + "_DivProgress").attr("data-percent", parseInt(FileUploader.Components[t_ElementName + "_TrasferCompletedRate"]).toFixed(0) + "%");
        /* ==== */

    }
    else {

        /* ==== */
        /* Hide the Progress Bar */
        $("#" + t_ElementName + "_DivProgress").hide();
        $("#" + t_ElementName + "_DivProgressBar").hide();
        $("#" + t_ElementName + "_DivProgressCancel").hide();
        $("#" + t_ElementName + "_DivProgressBar").css("width", "0%");
        $("#" + t_ElementName + "_DivProgress").attr("data-percent", "0%");
        FileUploader.Components[t_ElementName + "_ProgresssRate"] = 0;
        FileUploader.Components[t_ElementName + "_TrasferCompletedRate"] = 0;
        /* ==== */

    }
}
/* ==== */


/* ==== */
/* Help Guide Components Getter */
FileUploader.Components.Getter = function (Params) {

    /* Get the Component Values */
    var Response = {
        ElementName: Params.ElementName,
        FileName: Params.FileData.name,
        IsEOF: Params.StartRange >= Params.FileData.size ? true : false,
        ChunkIndex: FileUploader.Components[Params.ElementName.replace("_FileUploader", "") + "_ActiveChunks"],
        Base64String: Params.Base64String,
        DataPath: FileUploader.Components.RandomFolder,
        Category: FileUploader.Components.StyleName
    };
    return Response;
}
/* ==== */

/* ==== */
/* File Uploader Components Populate */
FileUploader.Components.Upload = function (Params) {
    /* Load the FileUploader Details */
    if (FileUploader.Components.Validation.Status(Params)) {

        /* Calculate the Total Transfer Chunk */
        var t_CResponse = FileUploader.Components.CalculateChunkProgresssRate(Params);
        if (t_CResponse != null) {
            FileUploader.Components.Setter(t_CResponse);

            /* Initiate the Recursive Requests */
            FileUploader.Components.RecursiveFileReader({
                ElementName: Params.ElementName,   /* File Uploader ElementId */
                FileData: Params.FileData,         /* Actual File */
                StartRange: 0                      /* Starting Offset Range (Startwith 0) */
            });
        }
    }
    /* ==== */
}
/* ==== */

/* ==== */
/* Read the File Data & Convert into Base64 */
FileUploader.Components.PauseRecursiveParams = null;
FileUploader.Components.RecursiveFileReader = function (Params) {

    /* Declearation */
    var t_FileReader = new FileReader();
    var t_SlicedChunkFile = null;
    var t_ChunkEndRange = 0;

    try {


        if (Params.FileData != null) {

            /* Set the Chunk Slice End Range */
            t_ChunkEndRange = (Params.StartRange + FileUploader.Components.ChunkSize);


            /* Get the Start & End Range */
            t_SlicedChunkFile = Params.FileData.slice(Params.StartRange, t_ChunkEndRange);

            /* Prepare reader with an event listener */
            t_FileReader.addEventListener('load', function (e) {

                /* Send the Current File Base64 String */
                Params.Base64String = e.target.result.split(';base64,')[1];
                var t_RequestParams = FileUploader.Components.Getter(Params);
                FileUploader.Components.Push(t_RequestParams);

                /* Check Is It Last Chunk */
                FileUploader.Components.PauseRecursiveParams = Params;
                if (!t_RequestParams.IsEOF && !FileUploader.Components.IsSkiped && !FileUploader.Components.IsWait) {

                    /* Read Next Chunk Using Recursive Method */
                    FileUploader.Components.RecursiveFileReader({

                        ElementName: Params.ElementName,   /* File Uploader ElementId */
                        FileData: Params.FileData,         /* Actual File */
                        StartRange: t_ChunkEndRange        /* Starting Range */

                    });

                } else {

                    /* ==== */
                    /* Upload Cancel then hide the Progress bar */
                    if (FileUploader.Components.IsSkiped && !FileUploader.Components.IsWait) {

                        /* Reset the Progress bar */
                        FileUploader.Components.Cleaner({
                            TargetId: Params.ElementName.replace("_FileUploader", "")  /* File Uploader ElementId */
                        });

                    }
                    /* ==== */
                }

            }, { once: true }); // register as a once handler!
            t_FileReader.readAsDataURL(t_SlicedChunkFile);

        }
    }
    catch (e) {

    }
}
/* ==== */

/* ==== */
/* File Uplader Data Recursively Send to Server */
FileUploader.Components.Push = function (Params) {
    if (Params != null) {
        DataControllers_FileUploader.Push(Params);
    }
}
/* ==== */
/* ==== */
/* FileUploader Validation Components Objects */
FileUploader.Components.Validation = {};
/* ==== */

/* ==== */
/* FileUploader Components Validation */
FileUploader.Components.Validation.Initialize = function () {

}
/* ==== */

/* ==== */
/* File Uploader Components Validation Status */
FileUploader.Components.Validation.Status = function (Params) {

    /* Declearation */
    var t_Boolean = false;
    var t_FileData = null;
    var t_ChunkSize = null;
    var t_MaxFileSize = null;

    /* ==== Mandatory Params ==== */
    /* Active File Data */
    if (typeof Params.FileData !== "undefined") {
        t_FileData = Params.FileData;
    }

    /* ==== Mandatory Params ==== */
    /* Default File Chunk Size Limit */
    if (typeof Params.ChunkSize !== "undefined") {
        t_ChunkSize = Params.ChunkSize;
    }

    /* ==== Mandatory Params ==== */
    /* Max File Upload Size Limit */
    if (typeof Params.MaxFileSize !== "undefined") {
        t_MaxFileSize = Params.MaxFileSize;
    }

    if (t_FileData == null) {
       
        /* Call the Clean Function */
        FileUploader.Components.Cleaner({
            TargetId: ".divUploadFiles"
        });

        /* Reset the Uploader */
        FileUploader.Components.UploaderReset();
        
    }
    else if (t_FileData.size > t_MaxFileSize) {

        /* ==== */
        /* File Size too large Message */
        $.gritter.add({
            title: "Warning",
            text: "Your File larger then 25MB",
            class_name: 'gritter-warning gritter-center'
        });
        /* ==== */

    }
    else {
        t_Boolean = true;
    }
    return t_Boolean;
}
/* ==== */


/* ==== */
/* Help Guide Documents Data Controllers */
class DataControllers_FileUploader {

    /* Receiver the Data from Server */
    static Push(Params) {


        /* ==== */
        /* Set the Progress Bar (Request) */
        if (!FileUploader.Components.IsSkiped) {
            FileUploader.Components.ProgressSetter({
                ElementName: Params.ElementName.replace("_FileUploader", ""),
                ProgressRate: FileUploader.Components[Params.ElementName.replace("_FileUploader", "") + "_ProgresssRate"]
            });
        }
        /* ==== */

        /* Move to Next Chunk */
        FileUploader.Components[Params.ElementName.replace("_FileUploader", "") + "_ActiveChunks"] += 1;

        $.ajax({
            type: "POST",
            url: "/FileUploader/SetFileChunks",
            data: Params,
            dataType: "text",
            async: false,
            success: function (Response) {
                if (Response != null) {
                    Response = JSON.parse(Response);
                    if (Response.status == "Success") {

                        var t_ElementName = Response.result.data1;
                        if (t_ElementName != "") {

                            t_ElementName = t_ElementName.replace("_FileUploader", "");

                            /* ==== */
                            /* Set the Progress Bar (Response) */
                            if (!FileUploader.Components.IsSkiped) {
                                FileUploader.Components.ProgressSetter({
                                    ElementName: t_ElementName,
                                    ProgressRate: FileUploader.Components[t_ElementName.replace("_FileUploader", "") + "_ProgresssRate"]
                                });
                            }
                            /* ==== */

                            /* ==== */
                            /* Success & Is Is Last Callback Function */
                            if (Response.result.data2) { /* EOF Flag */

                                /* Call the Clean Function */
                                FileUploader.Components.Cleaner({
                                    TargetId: t_ElementName
                                });

                                /* Reset the Uploader */
                                FileUploader.Components.UploaderReset();

                                /* Once Completed Callback */
                                if (typeof FileUploader.Components.UploadCompleted !== "undefined") {
                                    FileUploader.Components.UploadCompleted({
                                        TargetId: t_ElementName,
                                        FileIconPath: Response.result.data3,
                                        FilePath: Response.result.data4,
                                        FileType: Response.result.data5
                                    });
                                }
                            }
                            /* ==== */
                        }
                    }
                }
            },
            error: function (req, status, error) {
                alert(error);

            }
        });
    }
}
