/* ==== */
/* Form Details Components Objects */
var FormDet = {};
FormDet.Components = {};
/* ==== */

/* ==== */
/* Form Details Components Initialize */
FormDet.Components.Initialize = function () {

    /* Set Bread Crumb */
    GeneralFunction.SetBreadCrumb([{ Title: "Forms Details", Action: "#", Active: true }]);

    /* Load the Pagination Header  */
    FormDet.Components.Pagination.Initialize();

    /* Once Initialize Completed then Goto Ready State */
    FormDet.Components.Ready();

    /* Get the Form Details */
    FormDet.Components.Populate({
        Reset: false,
        ResetPagination: false
    });
}
/* ==== */

/* ==== */
/* Form Details Components Ready */
FormDet.Components.Ready = function () {

    /* Once Components Ready then Clean the Values  */
    FormDet.Components.Cleaner();

    /* Add Event Listener */
    FormDet.Components.AddEventListener();

}
/* ==== */


/* ==== */
/* Form Details Components Clean Up */
FormDet.Components.Cleaner = function () {

    /* Clean Up */
    $(".Search-Keyword-Input").val("");

}
/* ==== */


/* ==== */
/* Form Details Components Add Event Listener */
FormDet.Components.AddEventListener = function () {

    /* Best Practices For Remove Unused Event Listener */
    FormDet.Components.RemoveEventListener();

    /*  Search Click Event */
    $(".Search-Keyword-Input").on("keydown", function (event) {
        if (event.key == 'Enter') {

            /* Load the Class Details */
            FormDet.Components.Populate({
                Reset: true,
                ResetPagination: true
            });
        }
    });

    /* Pagination Populate Event */
    Pagination.Populate = function (Params) {

        /* Call the Class Populate */
        FormDet.Components.Populate({
            Reset: true,
            ResetPagination: true
        });
        
    }
}
/* ==== */

/* ==== */
/* Form Details Components Remove Active Event Listener */
FormDet.Components.RemoveEventListener = function () {
    /* Best Practices For Remove Unused Event Listener */
    $(".Search-Keyword-Input").off("keydown");
}
/* ==== */

/* ==== */
/* Form Details Data Processing PreLoader */
FormDet.Components.DataProcessing = function (Status) {
    GeneralFunction.DataProcessing(".table-FormDetails-Content", Status);
}
/* ==== */
/* ==== */
/* Form Details Component Setter */
FormDet.Components.Setter = function (Param) {


    /* Set the Pagination Configuration */
    Pagination.SetProperties({
        PageNo: Param.PageNo,
        TotalPages: Param.TotalPages
    })

    /* Set the Pagination Data */
    FormDet.Components.Pagination.TableBody(Param.Data);
}
/* ==== */

/* ==== */
/* Form Details Component Getter */
FormDet.Components.Getter = function (Param) {

    /* Check the Cookies Name & Configure the Search Component */
    GeneralFunction.GetSearchHistory(GeneralFunction.GetCurrentHashName(), function (Params) {

        /* Set the Search Keyword */
        $(".Search-Keyword-Input").val(Params.Pagination.Search);

        /* Set Pagination Component */
        Pagination.SetProperties({
            PageNo: Params.Pagination.PageNo,
            TotalPages: Params.Pagination.TotalPages
        });

    });

    /* Get the Component Values */
    var Response = {
        Pagination: Pagination.GetProperties()
    }

    /* Set Search History Details */
    GeneralFunction.SetCookies(GeneralFunction.GetCurrentHashName(), JSON.stringify(Response));
    return Response;
}
/* ==== */


/* ==== */
/* Form Details Component Back */
FormDet.Components.Back = function () {
    /* Goto Previows Screen */
}
/* ==== */

/* ==== */
/* Form Details Component Populate */
FormDet.Components.Populate = function (Params) {

    /* Clean the Pagination Components */
    if (typeof Params !== "undefined") {

        /* Reset the Current Page Configuration */
        if (typeof Params.ResetPagination !== "undefined") {

            if (Params.ResetPagination) {
                /* Student Academy History Pagination Clean-Up */
                FormDet.Components.Setter({
                    PageNo: 1,
                    TotalPages: 1,
                    Data: []
                });
            }

        }

        if (typeof Params.Reset !== "undefined") {
            if (Params.Reset) {

                /* Clear the Search History Cookies */
                GeneralFunction.RemoveCookies({
                    CookieName: GeneralFunction.GetCurrentHashName()
                });

                /* Clean the Data */
                FormDet.Components.Pagination.Cleaner();
            }
        }
    }

    /* Load the Form Details Details */
    DataControllers_FormDet.Pop(FormDet.Components.Getter());
    /* ==== */
}
/* ==== */

/* ==== */
/* Form Details Component Delete */
FormDet.Components.Delete = function (RouteId) {
    DataControllers_FormDet.Delete({
        FormId: RouteId
    });
}
/* ==== */


/* ==== */
/* Form Details Component Router */
FormDet.Components.Router = function (RouteId, RoutePage) {
    switch (RoutePage) {

        case "Edit":
            /* Set the Modify Form Routing */
            GeneralFunction.SetRouting("EditForm", RouteId);
            break;

        case "Delete":
            FormDet.Components.Pagination.DeleteRecord(RouteId);
            break;
    }
}
/* ==== */

/* ==== */
/* Form Details Pagination Components Objects */
FormDet.Components.Pagination = {}
FormDet.Components.Table = {
    HeadId: "#tbhFormDet",
    BodyId: "#tbdFormDet"
}
/* ==== */

/* ==== */
/* Form Details Components Initialize */
FormDet.Components.Pagination.Initialize = function () {

    /* Initialize Pagination Components */
    Pagination.Initialize({ EnableLazyLoad: true });

    /* Once Components Ready then Clean the Component Values */
    FormDet.Components.Pagination.Cleaner();

    /* Init the Pagination Table Header */
    FormDet.Components.Pagination.TableHead();

}
/* ==== */

/* ==== */
/* Form Components Table Clean */
FormDet.Components.Pagination.Cleaner = function () {

    try {

        /* Clear the Pagination Table Components */
        $(FormDet.Components.Table.BodyId).html("");

    }
    catch (ex) {

        /* ==== */
        /* Exception Message */
        GeneralFunction.Message({
            Status: "Failure",
            Title: "Failure",
            Message: ex.message,
        });
        /* ==== */
    }
}
/* ==== */

/* ==== */
/* Form Details Components Pagination Table Header */
FormDet.Components.Pagination.TableHead = function () {

    /* Declearation */
    var t_tr = null, t_th = null;

    try {

        /* Bind Table Column Details */
        t_tr = $(document.createElement("tr"));

        t_th = $(document.createElement("th"));
        t_th.text("FormId");
        t_th.addClass("hide");
        t_th.appendTo(t_tr);

        /* ==== */
        /* Desktop Preview */
        t_th = $(document.createElement("th"));
        t_th.text("Form Name");
        t_th.addClass("text-left col-lg-11 bolder background-gradient");
        t_th.appendTo(t_tr);

        t_th = $(document.createElement("th"));
        t_th.addClass("col-lg-1");
        t_th.text("");
        t_th.appendTo(t_tr);
        /* ==== */

        t_tr.appendTo(FormDet.Components.Table.HeadId);

    }
    catch (ex) {

        /* ==== */
        /* Exception Message Box Show */
        GeneralFunction.Message({
            Status: "Failure",
            Title: "Failure",
            Message: ex.message,
        });
        /* ==== */

    }
}
/* ==== */

/* ==== */
/* Form Details Components Pagination Table Body */
FormDet.Components.Pagination.TableBody = function (Result) {

    /* Declearation */
    var t_tr = null, t_td = null;

    try {

        /* ==== */
        /* Bind Table Column Values */
        for (var i = 0; i < Result.length; i++) {

            t_tr = $(document.createElement("tr"));
            t_tr.addClass("RN" + Result[i].FormId);

            t_td = $(document.createElement("td"));
            t_td.text(Result[i].FormId);
            t_td.addClass("hide");
            t_td.appendTo(t_tr);

            /* Form Name */
            t_td = $(document.createElement("td"));
            t_td.addClass("");
            t_td.text(Result[i].FormName);
            t_td.appendTo(t_tr);

            /* ==== */
            /* Edit / Delete */
            t_td = $(document.createElement("td"));
            t_td.attr("data-label", "");
            t_td.addClass("text-center hidden-xs hidden-sm");
            t_td.append('<a onclick =\"FormDet.Components.Router(' + Result[i].FormId + ',' + "'Edit'" + ')" href=\'javascript:void(0);\' title="Edit this Form"><i class=\"ace-icon fa fa-2x fa-pencil background-gradient\" aria-hidden=\"true\"></i></a>&nbsp; ');
            t_td.append('<a onclick =\"FormDet.Components.Router(' + Result[i].FormId + ',' + "'Delete'" + ')" href=\'javascript:void(0);\' title="Delete this Form"><i class="ace-icon fa fa-2x fas fa-trash red\" aria-hidden="true"></i></a>');
            t_td.appendTo(t_tr);
            /* ==== */

            t_tr.appendTo(FormDet.Components.Table.BodyId);
        }
        /* ==== */

    }
    catch (ex) {

        /* ==== */
        /* Exception Message Box Show */
        GeneralFunction.Message({
            Status: "Failure",
            Title: "Failure",
            Message: ex.message,
        });
        /* ==== */

    }
}

/* ==== */
/* FormDet Record Delete */
FormDet.Components.Pagination.DeleteRecord = function (RouteId) {

    var $window = $(window);
    var windowsize = $window.width();
    var width = "420";
    if (windowsize <= 480) {
        width = "95%";
    }

    $("#MdlDeleteConfirm").removeClass('hide').dialog({
        resizable: false,
        width: width,
        modal: true,
        title: "Delete",
        title_html: true,
        buttons: [
            {
                html: "Yes",
                "class": "btn btn-primary btn-xs btn-round bolder",
                click: function () {

                    /* Delete the Form */
                    FormDet.Components.Delete(RouteId);
                    $(this).dialog("close");
                }
            },
            {
                html: "No",
                "class": "btn btn-white btn-xs btn-round bolder",
                click: function () {
                    $(this).dialog("close");
                }
            }
        ]
    });

}
