/* Product Details Components Objects */
var ProductDet = {};
ProductDet.Components = {};
/* ==== */

/* ==== */
/* Product Details Components Initialize */
ProductDet.Components.Initialize = function () {

    /* Set Bread Crumb */
    GeneralFunction.SetBreadCrumb([{ Title: "Products Details", Action: "#", Active: true }]);

    /* Load the Pagination Header  */
    ProductDet.Components.Pagination.Initialize();

    /* Once Initialize Completed then Goto Ready State */
    ProductDet.Components.Ready();

    /* Get the Product Details */
    ProductDet.Components.Populate({
        Reset: false,
        ResetPagination: false
    });
}
/* ==== */

/* ==== */
/* Product Details Components Ready */
ProductDet.Components.Ready = function () {

    /* Once Components Ready then Clean the Values  */
    ProductDet.Components.Cleaner();

    /* Add Event Listener */
    ProductDet.Components.AddEventListener();

}
/* ==== */


/* ==== */
/* Product Details Components Clean Up */
ProductDet.Components.Cleaner = function () {

    /* Clean Up */
    $(".Search-Keyword-Input").val("");

}
/* ==== */


/* ==== */
/* Product Details Components Add Event Listener */
ProductDet.Components.AddEventListener = function () {

    /* Best Practices For Remove Unused Event Listener */
    ProductDet.Components.RemoveEventListener();

    /*  Search Click Event */
    $(".Search-Keyword-Input").on("keydown", function (event) {
        if (event.key == 'Enter') {

            /* Load the Class Details */
            ProductDet.Components.Populate({
                Reset: true,
                ResetPagination: true
            });
        }
    });

    /* Pagination Populate Event */
    Pagination.Populate = function (Params) {

        /* Call the Class Populate */
        ProductDet.Components.Populate({
            Reset: true,
            ResetPagination: true
        });
        
    }
}
/* ==== */

/* ==== */
/* Product Details Components Remove Active Event Listener */
ProductDet.Components.RemoveEventListener = function () {
    /* Best Practices For Remove Unused Event Listener */
    $(".Search-Keyword-Input").off("keydown");
}
/* ==== */

/* ==== */
/* Product Details Data Processing PreLoader */
ProductDet.Components.DataProcessing = function (Status) {
    GeneralFunction.DataProcessing(".table-ProductDetails-Content", Status);
}
/* ==== */
/* ==== */
/* Product Details Component Setter */
ProductDet.Components.Setter = function (Param) {


    /* Set the Pagination Configuration */
    Pagination.SetProperties({
        PageNo: Param.PageNo,
        TotalPages: Param.TotalPages
    })

    /* Set the Pagination Data */
    ProductDet.Components.Pagination.TableBody(Param.Data);
}
/* ==== */

/* ==== */
/* Product Details Component Getter */
ProductDet.Components.Getter = function (Param) {

    /* Check the Cookies Name & Configure the Search Component */
    GeneralFunction.GetSearchHistory(GeneralFunction.GetCurrentHashName(), function (Params) {

        /* Set the Search Keyword */
        $(".Search-Keyword-Input").val(Params.Pagination.Search);

        /* Set Pagination Component */
        Pagination.SetProperties({
            PageNo: Params.Pagination.PageNo,
            TotalPages: Params.Pagination.TotalPages
        });

    });

    /* Get the Component Values */
    var Response = {
        Pagination: Pagination.GetProperties()
    }

    /* Set Search History Details */
    GeneralFunction.SetCookies(GeneralFunction.GetCurrentHashName(), JSON.stringify(Response));
    return Response;
}
/* ==== */


/* ==== */
/* Product Details Component Back */
ProductDet.Components.Back = function () {
    /* Goto Previows Screen */
}
/* ==== */

/* ==== */
/* Product Details Component Populate */
ProductDet.Components.Populate = function (Params) {

    /* Clean the Pagination Components */
    if (typeof Params !== "undefined") {

        /* Reset the Current Page Configuration */
        if (typeof Params.ResetPagination !== "undefined") {

            if (Params.ResetPagination) {
                /* Student Academy History Pagination Clean-Up */
                ProductDet.Components.Setter({
                    PageNo: 1,
                    TotalPages: 1,
                    Data: []
                });
            }

        }

        if (typeof Params.Reset !== "undefined") {
            if (Params.Reset) {

                /* Clear the Search History Cookies */
                GeneralFunction.RemoveCookies({
                    CookieName: GeneralFunction.GetCurrentHashName()
                });

                /* Clean the Data */
                ProductDet.Components.Pagination.Cleaner();
            }
        }
    }

    /* Load the Product Details Details */
    DataControllers_ProductDet.Pop(ProductDet.Components.Getter());
    /* ==== */
}
/* ==== */

/* ==== */
/* Product Details Component Delete */
ProductDet.Components.Delete = function (RouteId) {
    DataControllers_ProductDet.Delete({
        ProductId: RouteId
    });
}
/* ==== */


/* ==== */
/* Product Details Component Router */
ProductDet.Components.Router = function (RouteId, RoutePage) {
    switch (RoutePage) {

        case "Edit":
            /* Set the Modify Product Routing */
            GeneralFunction.SetRouting("EditProduct", RouteId);
            break;

        case "Delete":
            ProductDet.Components.Pagination.DeleteRecord(RouteId);
            break;
    }
}
