/* Tax Components Ready */
Tax.Components.Ready = function () {

    /* Once Components Ready then Clean the Values  */
    Tax.Components.Cleaner();

    /* Add Event Listener */
    Tax.Components.AddEventListener();

    /* Populate the Data */
    Tax.Components.Populate($("#hdnTaxId").val());
}
