/* ==== */

/* ==== */
/* Tax Components Validation */
Tax.Components.Validation.Initialize = function (Params) {

    /* Home Screen Validation */
    /* Home Screen Validation */
    $('#frmTax').validate({
        errorElement: 'div',
        errorClass: 'help-block',
        focusInvalid: false,
        ignore: "",
        rules: {
            TaxName: {
                required: true
            },
            Phone: {
                required: true
            },
            AddressLine1: {
                required: true
            },
            AddressLine2: {
                required: true
            },
            AddressLine3: {
                required: true
            },
            City: {
                required: true
            },
            State: {
                required: true
            },
            PINCode: {
                required: true
            }
        },

        messages: {
            TaxName: {
                required: "Company Name Is Required."
            },
            Phone: {
                required: "Phone No Is Required."
            },
            AddressLine1: {
                required: "Address Line1 Is Required."
            },
            AddressLine2: {
                required: "Address Line2 Is Required."
            },
            AddressLine3: {
                required: "Address Line3 Is Required."
            },
            City: {
                required: "City Is Required."
            },
            State: {
                required: "State Is Required."
            },
            PINCode: {
                required: "PIN Code Is Required."
            }
        },

        highlight: function (e) {
            $(e).closest('.form-group').removeClass('has-info').addClass('has-error');
        },

        success: function (e) {
            $(e).closest('.form-group').removeClass('has-error'); //.addClass('has-info');
            $(e).remove();
        }
    });
}
/* ==== */

/* ==== */
/* Tax Components Validation Status */
Tax.Components.Validation.Status = function (Params) {

    var t_Boolean = true;
    if (!$('#frmTax').valid()) {
        t_Boolean = false;
    }
    return t_Boolean;
}
/* ==== */


/* ==== */
/* Tax Data Controllers */
class DataControllers_Tax {

    /* Send the Data to Server */
    static Puch(Params) {

        /* Transation Preloader Start */
        Tax.Components.SetProcessingState(true);

        $.ajax({
            type: "POST",
            url: "/Master/SetTax",
            data: Params,
            dataType: "text",
            success: function (Response) {

                /* Transation Preloader Stop */
                Tax.Components.SetProcessingState(false);

                Response = JSON.parse(Response);
                if (Response != null) {

                    /* ==== */
                    /* Message Box */
                    GeneralFunction.Message({
                        Status: Response.status,
                        Title: Response.status,
                        Message: Response.message
                    });
                    /* ==== */

                    /* ==== */
                    /* Response Routing */
                    if (Response.status == "Success") {

                        /* Clean Up */
                        Tax.Components.Cleaner();

                        /* Init the Dropdown List */
                        if (typeof Dropdown !== "undefined") {
                            if (typeof Dropdown.Tax !== "undefined") {
                                Dropdown.Tax.LoadDataFromServer({ PageName: "Cookies", ComponentId: ".divTax", ComponentValue: 0 });
                            }
                        }

                        /* Goto Back  */
                        if ($("#hdnTaxId").val() != "0") Tax.Components.Back();
                    }
                    /* ==== */
                }
            },
            error: function (req, status, error) {

                /* ==== */
                /* Exception Message Box Show */
                GeneralFunction.Message({
                    Status: "Failure",
                    Title: "Failure",
                    Message: error,
                });
                /* ==== */

                /* Transation Preloader Stop */
                Tax.Components.SetProcessingState(false);
            }
        });

    }

    /* Receiver the Data from Server */
    static Pop(Params) {

        $.ajax({
            type: "POST",
            url: "/Master/GetTax",
            data: Params,
            dataType: "text",
            success: function (Response) {

                if (Response != null) {
                    Response = JSON.parse(Response);
                    if (Response.status == "Success") {

                        /* ==== */
                        /* Set the Components Values */
                        Tax.Components.Setter(JSON.parse(Response.result));
                        /* ==== */

                    }
                }
            },
            error: function (req, status, error) {

                /* ==== */
                /* Exceoption Message Box Show */
                GeneralFunction.Message({
                    Status: "Failure",
                    Title: "Failure",
                    Message: error,
                });
                /* ==== */
            }
        });

    }


}
