/* Customer Details Components Pagination Table Header */
CustomerDet.Components.Pagination.TableHead = function () {

    /* Declearation */
    var t_tr = null, t_th = null;

    try {

        /* Bind Table Column Details */
        t_tr = $(document.createElement("tr"));

        t_th = $(document.createElement("th"));
        t_th.text("CustId");
        t_th.addClass("hide");
        t_th.appendTo(t_tr);

        /* ==== */
        /* Desktop Preview */
        t_th = $(document.createElement("th"));
        t_th.text("Name");
        t_th.addClass("text-left bolder background-gradient");
        t_th.appendTo(t_tr);

        t_th = $(document.createElement("th"));
        t_th.text("Contact No");
        t_th.addClass("text-left bolder background-gradient");
        t_th.appendTo(t_tr);

        t_th = $(document.createElement("th"));
        t_th.text("City");
        t_th.addClass("text-left bolder background-gradient");
        t_th.appendTo(t_tr);

        t_th = $(document.createElement("th"));
        t_th.text("GST No");
        t_th.addClass("text-left bolder background-gradient");
        t_th.appendTo(t_tr);

        t_th = $(document.createElement("th"));
        t_th.addClass("col-lg-1");
        t_th.text("");
        t_th.appendTo(t_tr);
        /* ==== */

        t_tr.appendTo(CustomerDet.Components.Table.HeadId);

    }
    catch (ex) {

        /* ==== */
        /* Exception Message Box Show */
        GeneralFunction.Message({
            Status: "Failure",
            Title: "Failure",
            Message: ex.message,
        });
        /* ==== */

    }
}
/* ==== */

/* ==== */
/* Customer Details Components Pagination Table Body */
CustomerDet.Components.Pagination.TableBody = function (Result) {

    /* Declearation */
    var t_tr = null, t_td = null;

    try {

        /* ==== */
        /* Bind Table Column Values */
        for (var i = 0; i < Result.length; i++) {

            t_tr = $(document.createElement("tr"));
            t_tr.addClass("RN" + Result[i].CustId);

            t_td = $(document.createElement("td"));
            t_td.text(Result[i].CustId);
            t_td.addClass("hide");
            t_td.appendTo(t_tr);

            /* Customer Name */
            t_td = $(document.createElement("td"));
            t_td.addClass("");
            t_td.text(Result[i].CustomerName);
            t_td.appendTo(t_tr);

            /* Contact No */
            t_td = $(document.createElement("td"));
            t_td.addClass("");
            t_td.text(Result[i].ContactNo);
            t_td.appendTo(t_tr);

            /* City */
            t_td = $(document.createElement("td"));
            t_td.addClass("");
            t_td.text(Result[i].City);
            t_td.appendTo(t_tr);

            /* GSTNo */
            t_td = $(document.createElement("td"));
            t_td.addClass("");
            t_td.text(Result[i].GSTNo);
            t_td.appendTo(t_tr);

            /* ==== */
            /* Edit / Delete */
            t_td = $(document.createElement("td"));
            t_td.attr("data-label", "");
            t_td.addClass("text-center hidden-xs hidden-sm");
            t_td.append('<a onclick =\"CustomerDet.Components.Router(' + Result[i].CustId + ',' + "'Edit'" + ')" href=\'javascript:void(0);\' title="Edit this Customer"><i class=\"ace-icon fa fa-2x fa-pencil background-gradient\" aria-hidden=\"true\"></i></a>&nbsp; ');
            t_td.append('<a onclick =\"CustomerDet.Components.Router(' + Result[i].CustId + ',' + "'Delete'" + ')" href=\'javascript:void(0);\' title="Delete this Customer"><i class="ace-icon fa fa-2x fas fa-trash red\" aria-hidden="true"></i></a>');
            t_td.appendTo(t_tr);
            /* ==== */

            t_tr.appendTo(CustomerDet.Components.Table.BodyId);
        }
        /* ==== */

    }
    catch (ex) {

        /* ==== */
        /* Exception Message Box Show */
        GeneralFunction.Message({
            Status: "Failure",
            Title: "Failure",
            Message: ex.message,
        });
        /* ==== */

    }
}

/* ==== */
/* CustomerDet Record Delete */
CustomerDet.Components.Pagination.DeleteRecord = function (RouteId) {

    var $window = $(window);
    var windowsize = $window.width();
    var width = "420";
    if (windowsize <= 480) {
        width = "95%";
    }

    $("#MdlDeleteConfirm").removeClass('hide').dialog({
        resizable: false,
        width: width,
        modal: true,
        title: "Delete",
        title_html: true,
        buttons: [
            {
                html: "Yes",
                "class": "btn btn-primary btn-xs btn-round bolder",
                click: function () {

                    /* Delete the Customer */
                    CustomerDet.Components.Delete(RouteId);
                    $(this).dialog("close");
                }
            },
            {
                html: "No",
                "class": "btn btn-white btn-xs btn-round bolder",
                click: function () {
                    $(this).dialog("close");
                }
            }
        ]
    });

}
/* ==== */



/* ==== */
/* Customer Details Data Controllers */
class DataControllers_CustomerDet {

    /* Send the Data to Server */
    static Puch(Params) {

    }

    /* Receiver the Data from Server */
    static Pop(Params) {

        /* Load the Data Preloader Start */
        CustomerDet.Components.DataProcessing(true);

        $.ajax({
            type: "POST",
            url: "/Customer/GetCustomerDetails",
            data: Params,
            dataType: "text",
            async: true,
            success: function (Response) {

                /* Load the Data Preloader Stop */
                CustomerDet.Components.DataProcessing(false);


                if (Response != null) {
                    Response = JSON.parse(Response);
                    if (Response.status == "Success") {

                        CustomerDet.Components.Setter({
                            PageNo: Response.result.value.pageNo,
                            TotalPages: Response.result.value.totalPages,
                            Data: JSON.parse(Response.result.value.data)
                        });

                    }
                }
            },
            error: function (req, status, error) {

                /* Load the Data Preloader Stop */
                CustomerDet.Components.DataProcessing(false);

                /* ==== */
                /* Exceoption Message Box Show */
                GeneralFunction.Message({
                    Status: "Failure",
                    Title: "Failure",
                    Message: error
                });
                /* ==== */
            }
        });


    }

    /* Delete the Data from Server */
    static Delete(Params) {

        $.ajax({
            type: "POST",
            url: "/Customer/DeleteCustomer",
            data: Params,
            dataType: "text",
            async: true,
            success: function (Response) {

                if (Response != null) {
                    Response = JSON.parse(Response);

                    /* ==== */
                    /* Message */
                    GeneralFunction.Message({
                        Status: Response.status,
                        Title: Response.status,
                        Message: Response.message
                    });
                    /* ==== */

                    if (Response.status == "Success") {
                        /* Refresh */
                        $(".RN" + Params.CustId).remove();
                    }
                }
            },
            error: function (req, status, error) {
                /* ==== */
                /* Exceoption Message Box Show */
                GeneralFunction.Message({
                    Status: "Failure",
                    Title: "Failure",
                    Message: error
                });
                /* ==== */
            }
        });
    }

}
/* ==== */
/* ==== */
/* Customer Components Objects */
var Customer = {};
Customer.Components = {};
/* ==== */

/* ==== */
/* Customer Components Initialize */
Customer.Components.Initialize = function () {

    /* Set the BreadCrumb */
    GeneralFunction.SetBreadCrumb([{ Title: "Party Ledger", Action: "#CustomerDetails" }, { Title: $("#hdnCustId").val() == "0" ? "Add New" : "Edit", Action: "#", Active: true }]);

    /* Once Init the Components Validation */
    Customer.Components.Validation.Initialize();

    /* Once Initialize Completed then Goto Ready State */
    Customer.Components.Ready();
}
/* ==== */

/* ==== */
/* Customer Components Ready */
Customer.Components.Ready = function () {

    /* Once Components Ready then Clean the Values  */
    Customer.Components.Cleaner();

    /* Add Event Listener */
    Customer.Components.AddEventListener();

    /* Populate the Data */
    Customer.Components.Populate($("#hdnCustId").val());
}
/* ==== */

/* ==== */
/* Customer Components Clean Up */
Customer.Components.Cleaner = function () {

    /* Set the Default Values */
    var CleanUp = {
        CustId: 0,
        CustomerName: "",
        ContactNo: "",
        EMail: "",
        AddressLine1: "",
        AddressLine2: "",
        PostCode: "",
        City: "",
        State: "",
        GSTNo: ""
    }

    Customer.Components.Setter(CleanUp);
}
/* ==== */

/* ==== */
/* Customer Components Add Event Listener */
Customer.Components.AddEventListener = function () {

    /* Best Practices For Remove Unused Event Listener */
    Customer.Components.RemoveEventListener();

    /* ==== */
    /* Save Click */
    $(".btn-save").on("click", function () {
        Customer.Components.Save();
    });
    /* ==== */

    /* ==== */
    /* Back Click */
    $(".btn-back").on("click", function () {
        Customer.Components.Back();
    });
    /* ==== */

    /* ==== */
    /* Get the PostCode Info */
    $("#txtPostCode").on("input", function (e) {

        // Remove all non-digit characters
        let t_PostCode = $(this).val().replace(/\D/g, "").substring(0, 6);

        // Update the textbox with cleaned value
        $(this).val(t_PostCode);
        if (!t_PostCode || t_PostCode.length < 6) {
            return;
        }
        

        // API URL (Replace with your own or use another suitable API)
        const url = `/Customer/GetPincodeInfo/${t_PostCode}`;
        $.get(url, function (data) {
            if (data.Status === "Success") {
                if (data.PostOffice.length > 0) {
                    // Extract the first post office data
                    const firstPostOffice = data.PostOffice[0];

                    // Set the extracted values to respective fields
                    $("#txtCity").val(firstPostOffice.District);
                    $("#txtState").val(firstPostOffice.State);
                }
            } else {
                // Clear fields in case of an error or no result
                $("#txtCity, #txtState").val("");
                alert("Invalid or unavailable postcode.");
            }
        }).fail(function (e) {
            // Handle API failure
            $("#txtCity, #txtState").val("");
            alert("Unable to fetch data. Please try again later.");
        });

    });
    /* ==== */

}
/* ==== */

/* ==== */
/* Customer Components Remove Active Event Listener */
Customer.Components.RemoveEventListener = function () {

    /* Best Practices For Remove Unused Event Listener */
    $(".btn-save").off("click");
    $(".btn-back").off("click");
}
/* ==== */

/* ==== */
/* Customer Button Processing Icon */
Customer.Components.SetProcessingState = function (Status) {

    /* Declearaction */
    GeneralFunction.TransPreloader(".btn-save", Status, "Processing...", false);
}
/* ==== */


/* ==== */
/* Customer Components Setter */
Customer.Components.Setter = function (Param) {

    /* Set the Component Values */
    typeof Param.CustomerName !== "undefined" ? $("#txtCustomerName").val(Param.CustomerName) : $("#txtCustomerName").val("");
    typeof Param.ContactNo !== "undefined" ? $("#txtCutomerContactNo").val(Param.ContactNo) : $("#txtCutomerContactNo").val("");
    typeof Param.EMail !== "undefined" ? $("#txtCutomerEMail").val(Param.EMail) : $("#txtCutomerEMail").val("");
    typeof Param.AddressLine1 !== "undefined" ? $("#txtAddressLine1").val(Param.AddressLine1) : $("#txtAddressLine1").val("");
    typeof Param.AddressLine2 !== "undefined" ? $("#txtAddressLine2").val(Param.AddressLine2) : $("#txtAddressLine2").val("");
    typeof Param.PostCode !== "undefined" ? $("#txtPostCode").val(Param.PostCode) : $("#txtPostCode").val("");
    typeof Param.City !== "undefined" ? $("#txtCity").val(Param.City) : $("#txtCity").val("");
    typeof Param.State !== "undefined" ? $("#txtState").val(Param.State) : $("#txtState").val("");
    typeof Param.GSTNo !== "undefined" ? $("#txtGSTNo").val(Param.GSTNo) : $("#txtGSTNo").val("");

}
/* ==== */

/* ==== */
/* Customer Components Getter */
Customer.Components.Getter = function (Param) {

    /* Get the Customer Response */
    var Response = {
        CustId: $("#hdnCustId").val(),
        CustomerName: $("#txtCustomerName").val(),
        EMail: $("#txtCutomerEMail").val(),
        ContactNo: $("#txtCutomerContactNo").val(),
        AddressLine1: $("#txtAddressLine1").val(),
        AddressLine2: $("#txtAddressLine2").val(),
        PostCode: $("#txtPostCode").val(),
        City: $("#txtCity").val(),
        State: $("#txtState").val(),
        GSTNo: $("#txtGSTNo").val()
    }
    return Response;
}
/* ==== */


/* ==== */
/* Customer Components Save */
Customer.Components.Save = function () {
    /* Send Resquest Server */
    if (Customer.Components.Validation.Status()) {
        DataControllers_Customer.Puch((Customer.Components.Getter({})));
    }
}
/* ==== */

/* ==== */
/* Customer Components Back */
Customer.Components.Back = function () {
    /* Goto Previows Screen */
    window.history.back();
}
/* ==== */

/* ==== */
/* Customer Components Populate */
Customer.Components.Populate = function (t_RouteId) {
    /* Load the Customer Details */
    if (t_RouteId != "0") {
        DataControllers_Customer.Pop({
            CustId: t_RouteId
        });
    }
    /* ==== */
}
