/* Purchase Print Components Clean Up */
PurchaseReturnPrint.Components.Cleaner = function () {

    /* Set the Default Values */
    var CleanUp = {
        BillNo: "",
        BillDate: new Date(),
        CustomerName: "",
        ContactNo: "",
        TotalQty: 0,
        DiscountPercentage: 0,
        DiscountAmount: 0,
        TaxPercentage: 0,
        TaxAmount: 0,
        TotalAmount: 0,
        SalesDetails: [],
        TaxDetails : []
    }
    PurchaseReturnPrint.Components.Setter(CleanUp);
}
