/* Repair Inward Details Component Setter */
RepairInwardDet.Components.Setter = function (Param) {

    /* Set the Pagination Configuration */
    Pagination.SetProperties({
        PageNo: Param.PageNo,
        TotalPages: Param.TotalPages
    })

    /* Set the Pagination Data */
    RepairInwardDet.Components.Pagination.TableBody(Param.Data);
}
