/* ==== */

/* ==== */
/* Sales Return Components Validation Status */
SalesmanInward.Components.Validation.Status = function (Params) {

    var t_Boolean = true;
    switch (Params.FormName) {
        case "SalesReturns":
            if (typeof Params.Data !== "undefined") {

                if (Params.Data.BillDate == "") {
                    /* ==== */
                    /* Message Box */
                    GeneralFunction.Message({
                        Status: "Failure",
                        Title: "Required",
                        Message: "Inv.Date is Required"
                    });
                    t_Boolean = false;
                    /* ==== */
                }
                else if (Params.Data.CustomerName == "") {
                    /* ==== */
                    /* Message Box */
                    GeneralFunction.Message({
                        Status: "Failure",
                        Title: "Required",
                        Message: "Customer Name is Required"
                    });
                    t_Boolean = false;
                    /* ==== */
                }
                else if (Params.Data.ContactNo === "" || Params.Data.ContactNo.length < 10 || !/^\d{10}$/.test(Params.Data.ContactNo)) {
                    /* ==== */
                    /* Message Box */
                    GeneralFunction.Message({
                        Status: "Failure",
                        Title: "Required",
                        Message: "Contact No is Required"
                    });
                    t_Boolean = false;
                    /* ==== */
                }
                else {
                    /* Check Product Details */
                    var t_ValidRows = 0;
                    var t_InValidRows = 0;
                    if (typeof Params.Data.ProductDetails !== "undefined") {
                        if (Params.Data.ProductDetails.length >= 0) {
                            for (var i = 0; i < Params.Data.ProductDetails.length; i++) {

                                var t_ProductCode = Params.Data.ProductDetails[i].ProductCode || "";
                                var t_ProductName = Params.Data.ProductDetails[i].ProductName || "";
                                var t_Rate = parseFloat(Params.Data.ProductDetails[i].Rate) || 0;
                                var t_Qty = parseFloat(Params.Data.ProductDetails[i].Qty) || 0;
                                var t_Weight = parseFloat(Params.Data.ProductDetails[i].SIWight) || 0;

                                if (t_ProductCode == "" || t_ProductName == "" || t_Qty <= 0 || t_Weight <= 0) {
                                    t_InValidRows += 1;
                                    $("#" + Params.Data.ProductDetails[i].RowIndex).addClass("alert alert-danger");
                                }
                                else {
                                    t_ValidRows += 1;
                                    $("#" + Params.Data.ProductDetails[i].RowIndex).removeClass("alert alert-danger");
                                }
                            }
                            if (t_ValidRows == 0) {

                                /* ==== */
                                /* Message Box */
                                GeneralFunction.Message({
                                    Status: "Failure",
                                    Title: "Required",
                                    Message: "Product is Required"
                                });
                                /* ==== */

                                t_Boolean = false;
                            }
                            else if (t_InValidRows > 0) {

                                /* ==== */
                                /* Message Box */
                                GeneralFunction.Message({
                                    Status: "Failure",
                                    Title: "Required",
                                    Message: "Kindly Complete All Product Details or Delete the row."
                                });
                                /* ==== */

                                t_Boolean = false;
                            }
                        }
                        else {
                            /* ==== */
                            /* Message Box */
                            GeneralFunction.Message({
                                Status: "Failure",
                                Title: "Required",
                                Message: "Product is Required"
                            });
                            /* ==== */
                            t_Boolean = false;
                        }
                    }
                }
            }

        case "Buyers":
            if (typeof Params.Data !== "undefined") {
                if (Params.Data.CustomerName == "") {
                    /* ==== */
                    /* Message Box */
                    GeneralFunction.Message({
                        Status: "Failure",
                        Title: "Required",
                        Message: "Customer Name is Required"
                    });
                    t_Boolean = false;
                    /* ==== */
                }
                else if (Params.Data.ContactNo == "") {
                    /* ==== */
                    /* Message Box */
                    GeneralFunction.Message({
                        Status: "Failure",
                        Title: "Required",
                        Message: "Contact No is Required"
                    });
                    t_Boolean = false;
                    /* ==== */
                }
            }
            break;
    }
    return t_Boolean;
}
/* ==== */


/* ==== */
/* Sales Return Data Controllers */
class DataControllers_SalesmanInward {

    /* Send the Data to Server */
    static Puch(Params) {

        /* Transation Preloader Start */
        SalesmanInward.Components.SetProcessingState(true);

        $.ajax({
            type: "POST",
            url: "/SalesmanInward/SetSalesmanInward",
            data: Params,
            dataType: "text",
            success: function (Response) {

                /* Transation Preloader Stop */
                SalesmanInward.Components.SetProcessingState(false);

                Response = JSON.parse(Response);
                if (Response != null) {

                    /* ==== */
                    /* Message Box */
                    GeneralFunction.Message({
                        Status: Response.status,
                        Title: Response.status,
                        Message: Response.message
                    });
                    /* ==== */

                    /* ==== */
                    /* Response Routing */
                    if (Response.status == "Success") {

                        /* Clean Up */
                        SalesmanInward.Components.Cleaner();

                        /* Goto Back  */
                        if ($("#hdnSalesmanInwardId").val() != "0") SalesmanInward.Components.Back();
                    }
                    /* ==== */
                }
            },
            error: function (req, status, error) {

                /* ==== */
                /* Exception Message Box Show */
                GeneralFunction.Message({
                    Status: "Failure",
                    Title: "Failure",
                    Message: error,
                });
                /* ==== */

                /* Transation Preloader Stop */
                SalesmanInward.Components.SetProcessingState(false);
            }
        });

    }

    /* Receiver the Data from Server */
    static Pop(Params) {

        $.ajax({
            type: "POST",
            url: "/SalesmanInward/GetSalesmanInward",
            data: Params,
            dataType: "text",
            success: function (Response) {

                if (Response != null) {
                    Response = JSON.parse(Response);
                    if (Response.status == "Success") {

                        /* ==== */
                        /* Set the Components Values */
                        SalesmanInward.Components.Setter(JSON.parse(Response.result));
                        /* ==== */

                    }
                }
            },
            error: function (req, status, error) {

                /* ==== */
                /* Exceoption Message Box Show */
                GeneralFunction.Message({
                    Status: "Failure",
                    Title: "Failure",
                    Message: error,
                });
                /* ==== */
            }
        });

    }
    
    /* Receiver the Data from Server */
    static PopSearchSalesDetails(Params) {

        $.ajax({
            type: "POST",
            url: "/SalesmanInward/GetMatchedSalesDetails",
            data: Params,
            dataType: "text",
            success: function (Response) {

                if (Response != null) {
                    Response = JSON.parse(Response);
                    if (Response.status == "Success") {
                        /* ==== */
                        /* Set the Components Values */
                        SalesmanInward.Components.SalesSetter(JSON.parse(Response.result));
                        /* ==== */
                    }
                }
            },
            error: function (req, status, error) {

                /* ==== */
                /* Exceoption Message Box Show */
                GeneralFunction.Message({
                    Status: "Failure",
                    Title: "Failure",
                    Message: error,
                });
                /* ==== */
            }
        });

    }

}
