/* ==== */
/* Purchase Print Components Initialize */
SalesmanInwardPrint.Components.Initialize = function () {

    /* Set the BreadCrumb */
    GeneralFunction.SetBreadCrumb([{ Title: "Print", Action: "#", Active: true }]);

    /* Once Initialize Completed then Goto Ready State */
    SalesmanInwardPrint.Components.Ready();
}
/* ==== */

/* ==== */
/* Purchase Print Components Ready */
SalesmanInwardPrint.Components.Ready = function () {

    /* Once Components Ready then Clean the Values  */
    SalesmanInwardPrint.Components.Cleaner();

    /* Add Event Listener */
    SalesmanInwardPrint.Components.AddEventListener();

    /* Populate the Data */
    SalesmanInwardPrint.Components.Populate($("#hdnSMINId").val());
}
/* ==== */

/* ==== */
/* Purchase Print Components Clean Up */
SalesmanInwardPrint.Components.Cleaner = function () {

    /* Set the Default Values */
    var CleanUp = {
        InwardNo: "",
        InwardDate: new Date(),
        SalesmanName: "",
        ContactNo: "",
        TotalQty: 0,
        DiscountPercentage: 0,
        DiscountAmount: 0,
        TaxPercentage: 0,
        TaxAmount: 0,
        TotalAmount: 0,
        ProductDetails: [],
        TaxDetails : []
    }
    SalesmanInwardPrint.Components.Setter(CleanUp);
}
/* ==== */

/* ==== */
/* Purchase Print Components Add Event Listener */
SalesmanInwardPrint.Components.AddEventListener = function () {

    /* Best Practices For Remove Unused Event Listener */
    SalesmanInwardPrint.Components.RemoveEventListener();

    /* ==== */
    /* Back Click */
    $(".btn-back").on("click", function () {
        SalesmanInwardPrint.Components.Back();
    });
    /* ==== */

}
/* ==== */

/* ==== */
/* Purchase Print Components Remove Active Event Listener */
SalesmanInwardPrint.Components.RemoveEventListener = function () {

    /* Best Practices For Remove Unused Event Listener */
    $(".btn-back").off("click");
}
/* ==== */

/* ==== */
/* Purchase Print Button Processing Icon */
SalesmanInwardPrint.Components.SetProcessingState = function (Status) {

    /* Declearaction */
    GeneralFunction.TransPreloader(".btn-save", Status, "Processing...", false);
}
/* ==== */


/* ==== */
/* Purchase Print Components Setter */
SalesmanInwardPrint.Components.Setter = function (Param) {
    
    /* Set the Customer Details */
    typeof Param.InwardNo !== "undefined" ? $(".lblInwardNo").html(Param.InwardNo) : $(".lblInwardNo").html("");
    typeof Param.InwardDate !== "undefined" ? $(".lblInwardDate").html(GeneralFunction.DateFormat(Param.InwardDate)) : $(".lblInwardDate").html("");
    typeof Param.OutwardNo !== "undefined" ? $(".lblOutwardNo").html(Param.OutwardNo) : $(".lblOutwardNo").html("");
    typeof Param.SalesmanName !== "undefined" ? $(".lblCustomerName").html(Param.SalesmanName) : $(".lblCustomerName").html("");
    typeof Param.ContactNo !== "undefined" ? $(".lblContactNo").html(Param.ContactNo) : $(".lblContactNo").html("");


    typeof Param.TotalDiscountPercentage !== "undefined" ? $(".lblDiscountPercentage").html(Param.TotalDiscountPercentage) : $(".lblDiscountPercentage").html("");
    typeof Param.TotalDiscountAmount !== "undefined" ? $(".lblDiscountAmount").html(parseFloat(Param.TotalDiscountAmount).toFixed(2)) : $(".lblDiscountAmount").html("");
    typeof Param.TaxPercentage !== "undefined" ? $(".lblTaxPercentage").html(Param.TaxPercentage) : $(".lblTaxPercentage").html("");
    typeof Param.GrandTotalAmount !== "undefined" ? $(".lblSummaryToPay").html("Grand Total  : " + parseFloat(Param.GrandTotalAmount).toFixed(2)) : $(".lblSummaryToPay").html("");


    /* Set the Tax Details */
    if (typeof Param.TaxDetails !== "undefined" && Param.TaxDetails.length > 0) {
        SalesmanInwardPrint.Components.TaxSetter(Param.TaxDetails);
    }

   
    /* Bind the Sales Details */
    var t_TotWeight = 0;
    var t_TotQty = 0;
    var t_TotAmount = 0;
    var t_TotDiscountAmt = 0;
    if (typeof Param.ProductDetails !== "undefined" && Param.ProductDetails.length > 0) {
        var $tbody = $(".tbdProductDetails");
        $tbody.empty(); // clear existing rows if any

        for (var i = 0; i < Param.ProductDetails.length; i++) {
            var item = Param.ProductDetails[i];
            var tr = $('<tr></tr>');
            tr.append('<td class="border-right p-all text-center bolder">' + (i + 1) + '</td>');
            tr.append('<td class="border-right p-all text-left bolder">' + (item.ProductCode || '') + '</td>');
            tr.append('<td class="border-right p-all text-left bolder">' + (item.ProductName || '') + '</td>');
            tr.append('<td class="border-right p-all text-left bolder">' + (item.BoxNo || '') + '</td>');
            tr.append('<td class="border-right p-all text-right bolder">' + parseFloat(item.Rate || 0).toFixed(2) + '</td>');
            tr.append('<td class="border-right p-all text-right bolder">' + parseFloat(item.SIWight || 0).toFixed(3) + '</td>');
            tr.append('<td class="border-right p-all text-center bolder">' + (item.Qty || 0) + '</td>');
            tr.append('<td class="border-right p-all text-right bolder">' + parseFloat(item.DiscountAmount || 0).toFixed(2) + '</td>');
            tr.append('<td class="border-right p-all text-right bolder">' + parseFloat(item.Amount || 0).toFixed(2) + '</td>');
            $tbody.append(tr);

            t_TotWeight += parseFloat(item.SIWight || 0);
            t_TotDiscountAmt += parseFloat(item.DiscountAmount || 0);
            t_TotQty += parseFloat(item.Qty || 0);
            t_TotAmount += parseFloat(item.Amount || 0);

        }
        $(".lblTotalQty").html(t_TotQty);
        $(".lblTotalWeight").html(parseFloat(t_TotWeight).toFixed(3));
        $(".lblTotalDiscount").html(parseFloat(t_TotDiscountAmt).toFixed(2));
        $(".lblTotalAmount").html(parseFloat(t_TotAmount).toFixed(2));
    }
}
