StockDet.Components.Router = function (RouteId, RoutePage) {
    switch (RoutePage) {

        case "Edit":
            /* Set the Modify Stock Routing */
            GeneralFunction.SetRouting("EditStock", RouteId);
            break;

        case "Delete":
            StockDet.Components.Pagination.DeleteRecord(RouteId);
            break;
    }
}
